// useLocalStorageState — useState that mirrors itself to localStorage.
// Returns the same shape as useState so it's a drop-in replacement.
// Defensive: read/write failures (private mode, quota, corrupt JSON)
// fall back to in-memory state without throwing.

import { useState, useEffect } from "react";

export function useLocalStorageState(key, defaultValue) {
  const [value, setValue] = useState(() => {
    try {
      const raw = window.localStorage.getItem(key);
      if (raw === null) {
        return typeof defaultValue === "function" ? defaultValue() : defaultValue;
      }
      return JSON.parse(raw);
    } catch {
      return typeof defaultValue === "function" ? defaultValue() : defaultValue;
    }
  });

  useEffect(() => {
    try {
      window.localStorage.setItem(key, JSON.stringify(value));
    } catch {
      /* quota / private mode — ignore */
    }
  }, [key, value]);

  return [value, setValue];
}
