import { useState } from "react";
import { CloudOff, RefreshCw, X } from "lucide-react";
import { useMarket } from "@/lib/MarketContext";
import { fmtTime } from "@/lib/parseItem";

// Shown when the Worker is unreachable and the page is being served
// from the localStorage fallback cache (Phase 8.3). Distinct from
// StaleDataBanner, which fires when the data is older than 7 days
// regardless of fetch health.
//
// `degraded` (from context) is non-null when at least one of the
// market/sellers fetches fell back to cache. Shape:
//   { market?: { at, error }, sellers?: { at, error } }
//
// This banner is intentionally narrow and uses red to signal "this
// isn't fresh, treat prices as direction-only" without blocking
// interaction with the rest of the page.
export default function OfflineBanner() {
  const { degraded, loading, refresh } = useMarket();
  const [dismissed, setDismissed] = useState(false);
  if (!degraded || dismissed) return null;

  const parts = [];
  if (degraded.market?.at) parts.push({ label: "market", at: degraded.market.at });
  if (degraded.sellers?.at) parts.push({ label: "sellers", at: degraded.sellers.at });
  // If neither has a timestamp, the live fetch failed AND no cache
  // exists — that's an unrecoverable failure, not a fallback. The
  // StaleDataBanner already covers "no data at all", so we let it
  // carry the message and skip the offline banner in that case.
  if (parts.length === 0) return null;

  const oldest = parts.reduce((a, p) => (p.at < a ? p.at : a), parts[0]?.at || Date.now());
  const ageMs = Date.now() - oldest;
  const stale = ageMs / (1000 * 60 * 60) > 24;

  return (
    <div
      data-testid="offline-banner"
      data-stale={stale ? "true" : "false"}
      className={`w-full border rounded-2xl p-4 mt-4 flex items-start gap-3 ${
        stale
          ? "bg-red-500/[0.08] border-red-500/30"
          : "bg-amber-500/[0.08] border-amber-500/25"
      }`}
      role="status"
    >
      <CloudOff className={`w-4 h-4 mt-0.5 shrink-0 ${stale ? "text-red-400" : "text-amber-400"}`} />
      <div className="flex-1 min-w-0">
        <div className={`font-mono text-[10px] uppercase tracking-[0.18em] font-bold ${stale ? "text-red-300" : "text-amber-300"}`}>
          Worker unreachable · showing cached data
        </div>
        <p className="text-zinc-400 text-sm mt-1 leading-relaxed">
          {parts.map((p, i) => (
            <span key={p.label}>
              {i > 0 ? " · " : ""}{p.label} cached {fmtTime(p.at)}
            </span>
          ))}
          {degraded.market?.error || degraded.sellers?.error ? (
            <span className="text-zinc-600"> — last error: {degraded.market?.error || degraded.sellers?.error}</span>
          ) : null}
        </p>
      </div>
      <div className="flex items-center gap-2 shrink-0">
        <button
          data-testid="offline-banner-retry"
          onClick={refresh}
          disabled={loading.market || loading.sellers}
          className={`inline-flex items-center gap-1.5 border ${
            stale
              ? "border-red-500/30 hover:border-red-400/60 hover:text-red-300 text-red-200"
              : "border-amber-500/30 hover:border-amber-400/60 hover:text-amber-300 text-amber-200"
          } font-bold uppercase tracking-[0.18em] text-[10px] px-3 py-1.5 rounded-sm transition-colors disabled:opacity-50 disabled:cursor-not-allowed`}
        >
          <RefreshCw className={`w-3 h-3 ${loading.market || loading.sellers ? "animate-spin" : ""}`} /> Retry
        </button>
        <button
          onClick={() => setDismissed(true)}
          aria-label="Dismiss offline banner"
          className="text-zinc-500 hover:text-zinc-300 transition-colors p-1"
        >
          <X className="w-4 h-4" />
        </button>
      </div>
    </div>
  );
}
